		import sailpoint.api.IdentityService;
		import sailpoint.api.SailPointContext;
		import sailpoint.object.ProvisioningPlan;
		import sailpoint.object.ProvisioningPlan.AccountRequest;
		import sailpoint.object.ProvisioningPlan.AttributeRequest;
		import sailpoint.object.Application;
		import sailpoint.object.Attributes;
		import sailpoint.object.Custom;
		import sailpoint.object.Link;
		import sailpoint.object.Identity;
		import sailpoint.tools.GeneralException;

		import java.util.ArrayList;
		import java.util.List;
		import java.util.Map;

		//log.debug("Check AD Domain Group");
		ProvisioningPlan plan = new ProvisioningPlan();

		Identity identity = context.getObjectByName(Identity.class, identityName);
		Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-DUO-InlineEnrollment");
		//log.error("AppNames in custom object*******"+custom.getAttributes().keySet());
		AccountRequest accReq = null;
		if(getDuoCreated(identity,"Duo")){
			List grps = null;
			String chkGrp=null;
			String addGrp=null;
			for (String appName: custom.getAttributes().keySet()) {
				grps = custom.get(appName);		
				for(String splitGroups:grps){
					chkGrp = splitGroups.split("##")[0];
					addGrp = splitGroups.split("##")[1];
					if (isAppExist(identityName, appName) @and isGroupExisted(identityName, chkGrp, appName) @and !isGroupExisted(identityName, addGrp, appName)) {
						accReq = new AccountRequest();
						accReq.setApplication(appName);
						accReq.setNativeIdentity(getNativeIdentity(identity, appName));
						accReq.setOperation(AccountRequest.Operation.Modify);
						accReq.add(new AttributeRequest("memberOf", ProvisioningPlan.Operation.Add, addGrp));
						accReq.add(new AttributeRequest("memberOf", ProvisioningPlan.Operation.Remove, chkGrp));
						plan.add(accReq);
					}
				}
			}		
		}else if (identity.getAttribute("employeeId") != null @or isAppExist(identityName, "Azure")) {
			List grps = null;
			String chkGrp=null;
			String addGrp=null;
			for (String appName: custom.getAttributes().keySet()) {
				grps = custom.get(appName);		
				for(String splitGroups:grps){
					chkGrp = splitGroups.split("##")[1];
					addGrp = splitGroups.split("##")[0];
					if (isAppExist(identityName, appName) @and isGroupExisted(identityName, chkGrp, appName) @and!isGroupExisted(identityName, addGrp, appName)) {
						accReq = new AccountRequest();
						accReq.setApplication(appName);
						accReq.setNativeIdentity(getNativeIdentity(identity, appName));
						accReq.setOperation(AccountRequest.Operation.Modify);
						accReq.add(new AttributeRequest("memberOf", ProvisioningPlan.Operation.Add, addGrp));
						plan.add(accReq);
					}
				}
			}
		}


		return plan;
